<?php

namespace App\Helpers;

class QuestionsHelper
{
    private static $questions = [
        ['id' => '2.1.1', 'category' => 'Master', 'text' => 'Were the Master and senior officers familiar with the company procedure for maintaining the vessel\'s statutory certification up to date, were all certificates and documents carried onboard up to date and was the vessel free of conditions of class or significant memoranda?'],
        ['id' => '2.2.1', 'category' => 'Master', 'text' => 'Had the vessel been attended by a company Superintendent at approximately six-monthly intervals and were reports available to demonstrate that a systematic vessel inspection had been completed during each attendance declared through the pre-inspection questionnaire?'],
        ['id' => '2.2.2', 'category' => 'Master', 'text' => 'Were recent ISM internal audit reports available on board, had corrective action been taken on board to close-out any non-conformities and had this corrective action been verified by shore management?'],
        ['id' => '2.2.3', 'category' => 'Master', 'text' => 'Was the Master fully conversant with the company\'s Safety Management System and had Master\'s Reviews of the system taken place in accordance with the ISM Code and company procedures?'],
        ['id' => '2.3.1', 'category' => 'Master and Chief Engineer', 'text' => 'Were the Master and Chief Engineer familiar with the company procedure to maintain the Enhanced Survey File in accordance with Classification Society rules, and was the vessel free of any visible or documentary evidence of concerns with the structural condition of the hull or cargo and ballast tank coatings?'],
        ['id' => '2.3.2', 'category' => 'Master and Chief Engineer', 'text' => 'Were the Master and Chief Engineer familiar with the company procedure to maintain the Class Survey File, and was the vessel free of any visible or documentary evidence of concerns with the structural condition of the hull or hold space and ballast tank coatings?'],
        ['id' => '2.3.3', 'category' => 'Master and Chief Officer', 'text' => 'Were the Master and senior officers familiar with the company cargo, ballast & void space inspection and reporting procedure and, were records available to demonstrate that all inspections had been accomplished within the required time frame with reports completed in accordance with company instructions?'],
        ['id' => '2.3.4', 'category' => 'Master and Chief Officer', 'text' => 'Were the Master and deck officers familiar with the company procedures for detecting leakage of liquids between cargo, bunker, ballast, void and cofferdam spaces which included inspecting the surface of ballast water prior to discharge, and were records available to show that the necessary checks had been performed?'],
        ['id' => '2.3.5', 'category' => 'Master', 'text' => 'Had the vessel been enrolled in a Classification Society Condition Assessment Programme (CAP)?'],
        ['id' => '2.4.1', 'category' => 'Master and Chief Engineer', 'text' => 'Were the senior officers familiar with the company procedure for reporting defects to vessel structure, machinery and equipment to shore-based management through the company defect reporting system and was evidence available to demonstrate that all defects had been reported accordingly?'],
        ['id' => '2.4.2', 'category' => 'Master', 'text' => 'Where defects existed to the vessel\'s structure, machinery or equipment, had the vessel operator notified class, flag and/or the authorities in the port of arrival, as appropriate to the circumstances, and had short term certificates, waivers, exemptions and/or permissions to proceed the voyage been issued where necessary?'],
        ['id' => '2.5.1', 'category' => 'Master and Chief Engineer', 'text' => 'Had the company Management of Change procedure been effectively implemented for changes affecting structure, machinery and equipment governed by Classification Society rules or statutory survey?'],
        ['id' => '2.6.1', 'category' => 'All Officers and Engineers', 'text' => 'Were the Master, deck officers and engineer officers familiar with the vessel\'s Ballast Water Management Plan and were records available to demonstrate that ballast handling had been conducted in accordance with the plan?'],
        ['id' => '2.6.2', 'category' => 'Master and Officers', 'text' => 'Were the Master and officers familiar with the VOC Management Plan, and had the procedures for minimising VOC emissions set out in the Plan been implemented and documented as required?'],
        ['id' => '2.6.3', 'category' => 'Master and Chief Engineer', 'text' => 'Were the Master and senior officers familiar with the contents and requirements of the Ship Energy Efficiency Management Plan (SEEMP) and had these been fully implemented?'],
        ['id' => '2.7.1', 'category' => 'Master', 'text' => 'Was the relevant content of the SMS manuals easily accessible to all personnel on board in a working language(s) understood by them?'],
        ['id' => '2.7.2', 'category' => 'Master', 'text' => 'Did the SMS identify clear levels of authority and lines of communication between the Master, ship\'s officers, ratings and the company, and were all onboard personnel familiar with these arrangements as they related to their position?'],
        ['id' => '2.8.1', 'category' => 'Master', 'text' => 'Was the OCIMF Harmonised Vessel Particulars Questionnaire (HVPQ) available through the OCIMF SIRE Programme database completed accurately to reflect the structure, outfitting, management and certification of the vessel?'],
        ['id' => '2.8.2', 'category' => 'Master', 'text' => 'Were records of the most recent Port State Control inspection available onboard, and where deficiencies had been recorded had these been corrected and closed out in accordance with the company procedure for defects or non-conformities?'],
        ['id' => '3.1.1', 'category' => 'Master', 'text' => 'Were the officers and ratings suitably qualified to serve onboard the vessel and did the officer matrix posted on the OCIMF website accurately reflect the qualifications, experience and English Language capabilities of the officers onboard at the time of the inspection?'],
        ['id' => '3.1.2', 'category' => 'Master', 'text' => 'Were procedures and instructions contained within the Safety Management System and signs posted around the vessel available in the designated working language of the vessel or a language(s) understood by the crew and, were the Master, officers and ratings able to communicate verbally in the designated working language?'],
        ['id' => '3.1.3', 'category' => 'Master', 'text' => 'Did the complement of officers and ratings onboard at the time of inspection meet or exceed the requirements of the Minimum Safe Manning Document and the declared company standard manning for routine operations, and had senior officers been relieved to ensure continuity of operational knowledge?'],
        ['id' => '3.2.1', 'category' => 'Master', 'text' => 'Was a report available onboard which confirmed that a static navigational assessment by a suitably qualified and experienced company representative had been completed as declared through the pre-inspection questionnaire?'],
        ['id' => '3.2.2', 'category' => 'Master', 'text' => 'Was a report available onboard which confirmed that a dynamic navigational assessment by a suitably qualified and experienced company representative had been completed while on passage as declared through the pre-inspection questionnaire?'],
        ['id' => '3.2.3', 'category' => 'Master', 'text' => 'Was a report available onboard which confirmed that a dynamic navigational assessment by a suitably qualified specialist contractor had been completed while on passage as declared through the pre-inspection questionnaire?'],
        ['id' => '3.2.4', 'category' => 'Master', 'text' => 'Was a report available onboard which confirmed that an unannounced remote navigational assessment, which included review of VDR & ECDIS data by an independent contractor or specialist company representative, had been completed as declared through the pre-inspection questionnaire?'],
        ['id' => '3.2.5', 'category' => 'Master and Chief Officer', 'text' => 'Was a report available onboard which confirmed that a comprehensive cargo audit by a suitably qualified and experienced company representative had been completed as declared through the pre-inspection questionnaire?'],
        ['id' => '3.2.6', 'category' => 'Chief Engineer', 'text' => 'Was a report available onboard which confirmed that a comprehensive engineering audit by a suitable qualified and experienced company representative had been completed as declared in the pre-inspection questionnaire?'],
        ['id' => '3.2.7', 'category' => 'Master', 'text' => 'Was a report available onboard which confirmed that a comprehensive mooring and anchoring audit by a suitably qualified and experienced company representative had been completed as declared through the pre-inspection questionnaire?'],
        ['id' => '3.2.8', 'category' => 'Master', 'text' => 'Had the vessel operator implemented a Behavioural Competency Assessment Programme onboard and was there evidence available that assessments were being conducted for navigation, cargo, mooring and engineering operations by approved assessors?'],
        ['id' => '3.3.1', 'category' => 'Master', 'text' => 'Had the Master and all navigation officers attended a shore-based Bridge Team Management training course within the previous five years?'],
        ['id' => '3.3.2', 'category' => 'Master', 'text' => 'Had the Master received formal ship handling training prior to promotion or when being assigned to a new type of ship having significantly different handling characteristics to ships in which they had recently served?'],
        ['id' => '3.3.3', 'category' => 'Master', 'text' => 'Had the Master, deck officers, and cargo/gas engineer where carried, attended a shore-based simulator course covering routine and emergency cargo operations within the previous five years?'],
        ['id' => '3.3.4', 'category' => 'Chief Engineer', 'text' => 'Had the Chief Engineer and all engineer officers attended a shore-based engine room management simulator course covering routine and emergency machinery operations within the previous five years?'],
        ['id' => '3.4.1', 'category' => 'Master', 'text' => 'Was there an effective system in place to record and monitor the hours of rest for all personnel onboard in compliance with STCW, MLC or the regulatory requirements applicable to the vessel?'],
        ['id' => '3.4.2', 'category' => 'Master and All', 'text' => 'Were the Master, officers and crew familiar with the company policy and procedures for drug and alcohol abuse prevention and had unannounced drug and alcohol testing taken place onboard in accordance with the policy?'],
        ['id' => '3.5.1', 'category' => 'Master and Officers', 'text' => 'Had the company developed an effective familiarisation programme that covered the personal safety and professional responsibilities of all onboard personnel, including visitors and contractors, and were records available to demonstrate that the familiarisation had been completed as required?'],
        ['id' => '3.5.2', 'category' => 'Master and All', 'text' => 'Were the Master, officers and ratings familiar with the ship\'s lifesaving and fire extinguishing appliances and, had ongoing onboard training and instruction taken place to maintain familiarity?'],
        ['id' => '3.5.3', 'category' => 'Master and Officers', 'text' => 'Had the Master and navigation officers been familiarised with the ECDIS equipment installed on board and were documented records of this familiarisation available?'],
        ['id' => '4.1.1', 'category' => 'Master and Officers', 'text' => 'Were the Master and navigation officers familiar with the company procedures for the set up and operation of the ECDIS units fitted to the vessel and were records available to demonstrate that the ECDIS had been operated in accordance with company procedures at all stages of a voyage?'],
        ['id' => '4.1.2', 'category' => 'Master and Officers', 'text' => 'Were the Master and navigation officers familiar with the company procedures for managing and operating the radar/ARPA units fitted to the vessel, and were records available to demonstrate that the units had been operated and tested in accordance with company procedures?'],
        ['id' => '4.1.3', 'category' => 'Master and Officers', 'text' => 'Were the Master and navigation officers familiar with the company procedures for operating and testing the steering control systems fitted to the vessel and were records available to demonstrate that operation and testing had been carried out in accordance with the procedures?'],
        ['id' => '4.1.4', 'category' => 'Master and Officers', 'text' => 'Were the Master and navigation officers familiar with the company procedures for using the Automatic Identification System (AIS) fitted to the vessel and were records available to confirm that periodic checks and tests had been carried out in accordance with the procedures?'],
        ['id' => '4.1.5', 'category' => 'Master and Officers', 'text' => 'Were the Master and navigation officers familiar with the company procedure for the use of the Bridge Navigational Watch Alarm System (BNWAS) and were records available to demonstrate that it had been operated and tested in accordance with the procedure?'],
        ['id' => '4.1.6', 'category' => 'Master and Officers', 'text' => 'Were the Master and navigation officers familiar with the company procedures governing the management and operation of the Global Navigation Satellite System (GNSS) receivers fitted onboard and was the fitted equipment configured, used and checked in accordance with the procedure?'],
        ['id' => '4.1.7', 'category' => 'Master and Officers', 'text' => 'Were the Master and navigation officers familiar with the company procedures for operating and managing the echo sounder and were records maintained to demonstrate that the equipment fitted to the vessel had been tested and operated in accordance with the company expectations?'],
        ['id' => '4.1.8', 'category' => 'Master and Officers', 'text' => 'Were the Master and navigation officers familiar with the company procedures for the operation and testing of the speed and distance measuring devices fitted to the vessel and were records available to demonstrate that periodic tests had been completed as required by the procedures?'],
        ['id' => '4.1.9', 'category' => 'Master and Officers', 'text' => 'Were the Master and navigation officers familiar with the company procedures for the use and testing of the navigation lights and shapes, and was there evidence that the navigation lights had been tested to confirm full functionality and correct visibility?'],
        ['id' => '4.1.10', 'category' => 'Master and Officers', 'text' => 'Were the Master and navigation officers familiar with the company procedure for managing Marine Safety Information broadcasts by NAVTEX and SafetyNET and were warnings affecting the vessel\'s route plotted on the voyage charts?'],
        ['id' => '4.1.11', 'category' => 'Master and Officers', 'text' => 'Were the Master and navigation officers familiar with the company procedure for preserving data from the VDR/S-VDR and were records available to demonstrate that tests of the equipment had been completed as required?'],
        ['id' => '4.1.12', 'category' => 'Master and Officers', 'text' => 'Were the Master and navigation officers familiar with the company procedures relating to the magnetic and gyro compasses carried onboard, and were records available to demonstrate their accuracy and reliability?'],
        ['id' => '4.1.13', 'category' => 'Master and Officers', 'text' => 'Were the Master and navigation officers familiar with the company procedures for the operation and testing of the VHF/DSC transceivers fitted to the vessel, and were records available to demonstrate that periodic tests and checks had been completed in accordance with company expectations?'],
        ['id' => '4.1.14', 'category' => 'Master and Officers', 'text' => 'Were the Master and navigation officers familiar with the company procedure for testing and using the daylight signalling lamp?'],
        ['id' => '4.1.15', 'category' => 'Master and Officers', 'text' => 'Were the Master and navigation officers familiar with the company procedures for the use and testing of the sound signalling equipment fitted to the vessel and were records available to confirm that periodic tests had been completed and the equipment used in accordance with company expectations?'],
        ['id' => '4.2.1', 'category' => 'Master and Officers', 'text' => 'Were the Master and navigating officers familiar with the company passage planning procedures and had all voyages been appraised, planned, executed and monitored in accordance with company procedures, industry best practice and both local and international rules?'],
        ['id' => '4.2.2', 'category' => 'Master and Officers', 'text' => 'Were the Master and navigation officers familiar with the company under keel clearance (UKC) policy and procedure, and were records available to demonstrate that the required calculations had been completed at the appropriate points during each voyage and the vessel had remained in compliance with the UKC policy?'],
        ['id' => '4.2.3', 'category' => 'Master and Officers', 'text' => 'Had the Master prepared Master\'s Standing Orders, supplemented by Daily Orders, which emphasised and reinforced the company expectations with regards to navigational requirements including restricted visibility, CPA/BCR and minimum passing distance from navigational dangers and navigational aids and, if so, had all navigation officers signed to acknowledge their understanding of the same?'],
        ['id' => '4.2.4', 'category' => 'Master and Officers', 'text' => 'Were the Master and navigation officers familiar with the company electronic chart management procedures and were onboard ENCs and RNCs managed, corrected and used appropriately?'],
        ['id' => '4.2.5', 'category' => 'Master and Officers', 'text' => 'Were the Master and navigation officers familiar with the company paper chart management procedures and were onboard paper charts managed, corrected and used appropriately?'],
        ['id' => '4.2.6', 'category' => 'Master and Officers', 'text' => 'Were the Master and navigation officers familiar with the company procedures for testing the navigational equipment, main propulsion, steering gear and thrusters prior to use and prior to critical phases of a passage or operation and, did checklists or logbook entries confirm the required tests had been completed as required?'],
        ['id' => '4.2.7', 'category' => 'Master and Officers', 'text' => 'Were the Master and navigation officers familiar with the company procedure for the carriage and management of nautical publications and was evidence available to demonstrate that publications had been managed in accordance with the procedure?'],
        ['id' => '4.3.1', 'category' => 'Master and Officers', 'text' => 'Were the master and navigation officers familiar with the company procedures defining the minimum bridge team composition and engine room operating mode and were records available to demonstrate that recent voyages had been planned and executed in accordance with company expectations?'],
        ['id' => '4.3.2', 'category' => 'Chief Engineer and Engineers', 'text' => 'Were the engineer officers familiar with the company procedures defining machinery space operating mode and, where required to be attended, the machinery space team composition during the various stages of a voyage, and were records available to confirm the machinery space had been operated accordingly?'],
        ['id' => '4.3.3', 'category' => 'Master and Officers', 'text' => 'Were the Master and navigation officers familiar with the company procedures for integrating a pilot (or similar role*) into the bridge team and were records available to demonstrate that the process had been followed?'],
        ['id' => '4.3.4', 'category' => 'Master and Officers', 'text' => 'Were the Master and navigation officers familiar with the company procedures to prevent disruption and distraction on the bridge, and were these procedures being complied with?'],
        ['id' => '4.4.1', 'category' => 'Master and Officers', 'text' => 'Were the Master and Officers familiar with the operation of the Emergency Position Indicating Radio Beacon (EPIRB) and was the EPIRB in good order with records available to demonstrate that had it been inspected, tested and maintained as required?'],
        ['id' => '4.4.2', 'category' => 'Master and Officers', 'text' => 'Were the Master and officers familiar with the operation of the Search and Rescue Transmitters (SARTs), and were the SARTs in good order with records available to demonstrate that had they had been inspected and tested as required?'],
        ['id' => '4.4.3', 'category' => 'Master and Officers', 'text' => 'Were the Master and Officers familiar with the location, purpose and operation of the survival craft portable two-way VHF radios and were they in good order with records available to demonstrate that had they been inspected and tested as required?'],
        ['id' => '4.4.4', 'category' => 'Master and Officers', 'text' => 'Were the Master and navigation officers familiar with the procedures for sending and receiving distress, urgency and safety messages and were suitable instructions posted by the GMDSS equipment?'],
        ['id' => '4.4.5', 'category' => 'Master and Officers', 'text' => 'Were the Master and navigation officers familiar with the operation, testing and maintenance of the GMDSS VHF, MF and HF radio and satellite communications equipment and were records available to demonstrate the equipment was in good order?'],
        ['id' => '4.4.6', 'category' => 'Master and Officers', 'text' => 'Were the Master, officers and crew aware of the potential danger of using radio or mobile telephone equipment during cargo and ballast handling operations and was there a sufficient number of intrinsically safe portable radios for use in operational areas?'],
        ['id' => '5.1.1', 'category' => 'Master and Officers', 'text' => 'Were the Master and officers familiar with the onboard emergency response plans, and were records available to demonstrate that all mandatory and company defined emergency drills had been completed and documented as required by company procedures?'],
        ['id' => '5.1.2', 'category' => 'Master and Officers', 'text' => 'Were the Master and officers familiar with the shipboard emergency plans for the principal fire scenarios for the vessel type, and had drills taken place to test the effectiveness of the plans in accordance with the company procedures?'],
        ['id' => '5.1.3', 'category' => 'Master and Officers', 'text' => 'Were the Master and officers familiar with the vessel\'s SOPEP or SMPEP, and had drills taken place to test the effectiveness of the onboard emergency response actions required by the Plan and company procedures?'],
        ['id' => '5.1.4', 'category' => 'Master and Officers', 'text' => 'Were the Master and officers familiar with the shipboard emergency plan for enclosed space rescue, and had drills taken place to test the effectiveness of the shipboard emergency response plan in accordance with company procedures?'],
        ['id' => '5.1.5', 'category' => 'Master and Chief Officer', 'text' => 'Were the Master and Ship Security Officer (SSO) familiar with the vessel\'s Ship Security Plan (SSP), and had drills taken place to test the effectiveness of the measures and procedures specified by the Ship Security Plan?'],
        ['id' => '5.1.6', 'category' => 'Master and Officers', 'text' => 'Were the Master, officers and ratings familiar with the procedure for launching the lifeboat(s), and had abandon ship drills taken place in accordance with company procedures and the requirements of SOLAS and the Flag Administration?'],
        ['id' => '5.1.7', 'category' => 'Master and Officers', 'text' => 'Were the Master and officers familiar with the shipboard emergency plan for a cargo vapour or liquid release, Including potential fire,  and had drills taken place to test the effectiveness of the shipboard emergency response plan in accordance with company procedures?'],
        ['id' => '5.1.8', 'category' => 'Master and Officers', 'text' => 'Were the Master and officers familiar with the shipboard emergency plan for collision, and had drills taken place to test the effectiveness of the shipboard emergency response plan in accordance with company procedures?'],
        ['id' => '5.1.9', 'category' => 'Master and Officers', 'text' => 'Were the Master and officers familiar with the shipboard emergency plan for grounding, and had drills taken place to test the effectiveness of the shipboard emergency response plan in accordance with company procedures?'],
        ['id' => '5.1.10', 'category' => 'Master and Officers', 'text' => 'Were the Master and officers familiar with the shipboard emergency plan for loss of propulsion, and had drills taken place to test the effectiveness of the shipboard emergency response plan in accordance with company procedures?'],
        ['id' => '5.1.11', 'category' => 'Master and All', 'text' => 'Were the Master and officers familiar with the shipboard emergency plan for failure of electrical power, and had drills taken place to test the effectiveness of the shipboard emergency response plan in accordance with company procedures?'],
        ['id' => '5.1.12', 'category' => 'Master and All', 'text' => 'Were the Master and officers familiar with the shipboard emergency plan for steering gear failure, and had drills taken place to test the effectiveness of the shipboard emergency response plan in accordance with company procedures.'],
        ['id' => '5.1.13', 'category' => 'Master and All', 'text' => 'Were the Master and officers familiar with the shipboard emergency plan for emergency towing, including the Emergency Towing Booklet (ETB), and had drills taken place to test the effectiveness of the shipboard emergency response plan in accordance with company procedures?'],
        ['id' => '5.1.14', 'category' => 'Master and All', 'text' => 'Were the Master, officers and ratings familiar with the shipboard emergency response plan for man overboard, including the launching and recovering the rescue boat, and had drills taken place to test the effectiveness of the shipboard emergency response plan in accordance with company procedures?'],
        ['id' => '5.1.15', 'category' => 'Master and All', 'text' => 'Were the Master, officers and ratings familiar with the shipboard emergency response plan for recovery of persons from the water, and had drills taken place to test the effectiveness of the shipboard emergency response plan in accordance with company procedures?'],
        ['id' => '5.1.16', 'category' => 'Master and All', 'text' => 'Were the Master and officers familiar with the shipboard emergency plans for flooding, and had drills taken place to test the effectiveness of the shipboard emergency response plans in accordance with company procedures?'],
        ['id' => '5.1.18', 'category' => 'Master and All', 'text' => 'Were the Master and officers familiar with the company procedures setting out the actions to be taken in the event of a cargo leak into a double hull tank, and was all required equipment available and in satisfactory condition?'],
        ['id' => '5.1.19', 'category' => 'Master and All', 'text' => 'Were the Master and officers familiar with the emergency arrangements to pump out the spaces forward of the collision bulkhead in the event of flooding and were these arrangements prominently marked and in good order?'],
        ['id' => '5.2.1', 'category' => 'Master and All', 'text' => 'Were the Master, officers and ratings familiar with the starting procedure for the emergency fire pump, and were records available to demonstrate that the emergency fire pump and its location had been maintained and tested in accordance with company procedures?'],
        ['id' => '5.2.2', 'category' => 'Master and All', 'text' => 'Were the Master, officers and crew familiar with the location, purpose, testing and operation of the vessel\'s fire dampers, the means of closing the main inlets and outlets of all ventilation systems and the means of stopping the power ventilation systems from outside the space served?'],
        ['id' => '5.2.3', 'category' => 'Master and All', 'text' => 'Were the Master and officers familiar with the location, purpose and operation of the vessel\'s fixed fire detection and fire alarm system, and was the equipment in good working order, regularly inspected, tested and maintained?'],
        ['id' => '5.2.4', 'category' => 'Master and All', 'text' => 'Were the Master and officers familiar with the location, purpose and operation of the vessel\'s fixed carbon dioxide fire extinguishing system, and was the equipment in good working order and available for immediate use, with the release procedure and operating instructions displayed at the control stations?'],
        ['id' => '5.2.5', 'category' => 'Master and All', 'text' => 'Were the Master and officers familiar with the location, purpose and operation of the vessel\'s machinery space fixed high-expansion foam fire extinguishing system, and was the equipment in good working order, available for immediate use, and with operating instructions clearly displayed at the control stations?'],
        ['id' => '5.2.6', 'category' => 'Master and All', 'text' => 'Were the Master and officers familiar with the location, purpose and operation of the vessel\'s machinery space fixed pressure water-spraying fire extinguishing system, and was the equipment in good working order and available for immediate use, with operating instructions clearly displayed at the control stations?'],
        ['id' => '5.2.7', 'category' => 'Master and All', 'text' => 'Were the Master and officers familiar with the location, purpose and operation of the vessel\'s fire pumps, fire main, fire main isolating valves and fire hydrants, and was the system and its components in good working order and available for immediate use?'],
        ['id' => '5.2.8', 'category' => 'Master and All', 'text' => 'Were the Master, officers and galley staff familiar with the location, purpose and operation of the fixed and portable fire extinguishing systems provided in the galley, were the systems in good working order and available for immediate use, and were galley ranges, exhaust vents, filter cowls free of grease or combustible material?'],
        ['id' => '5.2.9', 'category' => 'Master and All', 'text' => 'Were the Master and officers familiar with the location, purpose and operation of the water-spray system for cooling, fire prevention and crew protection on deck, and was the equipment in good working order, regularly inspected, tested and maintained?'],
        ['id' => '5.2.12', 'category' => 'Master and All', 'text' => 'Were the Master and officers familiar with the location, purpose and operation of the fixed fire-extinguishing system in the vessel\'s paint locker and any other flammable liquid locker, and was the system in good working order and available for immediate use?'],
        ['id' => '5.2.13', 'category' => 'Master and All', 'text' => 'Were the Master and officers familiar with the location, purpose and operation of the machinery space fixed water-based or equivalent local application fire-fighting system, and was the equipment in good working order and readily available for immediate use, with operating instructions clearly displayed at the control stations?'],
        ['id' => '5.2.14', 'category' => 'Chief Officer', 'text' => 'Were the Master and officers familiar with the purpose of the cargo, ballast and stripping pump temperature sensing devices, and was there evidence that alarm activation points had been correctly set and tested in accordance with company procedures and manufacturer\'s instructions?'],
        ['id' => '5.2.15', 'category' => 'Master and All', 'text' => 'Were the Master, officers and ratings familiar with the purpose and operation of the vessel\'s deck foam system, including portable applicators, and was the system in good working order and available for immediate use, with operating instructions displayed at the control station?'],
        ['id' => '5.2.16', 'category' => 'Master and All', 'text' => 'Were the Master, officers and crew familiar with the location, purpose, testing and operation of the vessel\'s fire doors?'],
        ['id' => '5.3.1', 'category' => 'Master and All', 'text' => 'Were the Master, officers and ratings familiar with the location and use of the vessel\'s firefighter\'s outfits including the self-contained breathing apparatus (SCBA), and was the equipment maintained in good condition and ready for immediate use in accordance with company procedures?'],
        ['id' => '5.3.2', 'category' => 'Master and All', 'text' => 'Were the Master, officers and crew familiar with the location, purpose and operation of the vessel\'s fire hoses, nozzles and international shore connection, and was the equipment in good working order and available for immediate use?'],
        ['id' => '5.3.3', 'category' => 'Master and All', 'text' => 'Were the Master, officers and ratings familiar with the location, purpose and operation of the vessel\'s portable fire extinguishers, and were the extinguishers in good order and readily available for immediate use with operating instructions clearly marked?'],
        ['id' => '5.3.4', 'category' => 'Master and All', 'text' => 'Were the Master, officers and ratings familiar with the location and purpose of the Emergency Escape Breathing Devices (EEBDs) carried on board, and were these devices in good order, suitably located and ready for immediate use?'],
        ['id' => '5.3.5', 'category' => 'Master and All', 'text' => 'Were the Master, officers and engine ratings familiar with the purpose and operation of the vessel\'s wheeled (mobile) fire extinguishers, and was the equipment in good order and available for immediate use with operating instructions clearly marked?'],
        ['id' => '5.4.1', 'category' => 'Master and All', 'text' => 'Were the Master and officers familiar with the operation of the davit-launched lifeboats, release mechanisms and launching appliances, and were they in good order with records available to demonstrate that they had been inspected and tested as required?'],
        ['id' => '5.4.2', 'category' => 'Master and All', 'text' => 'Were the Master and officers familiar with the operation of the free-fall lifeboat, its release systems and its launching appliance, and was the equipment in satisfactory condition with records available to demonstrate that it had been inspected and tested in accordance with company procedures?'],
        ['id' => '5.4.3', 'category' => 'Master and All', 'text' => 'Were the Master and officers familiar with the operation of the dedicated rescue boat and launching appliance, and were they in good order with records available to demonstrate that they had been inspected and tested as required?'],
        ['id' => '5.4.4', 'category' => 'Master and All', 'text' => 'Were the Master and Officers familiar with the location, purpose and operation of the rocket parachute flares and line throwing appliances and were they in good order, with records available to demonstrate that had they had been inspected as required?'],
        ['id' => '5.4.5', 'category' => 'Master and All', 'text' => 'Were the Master and officers familiar with the operation of the liferafts, hydrostatic releases and liferaft launching appliances, where provided, and were they in good order with records available to demonstrate that they had been serviced, inspected and tested as required?'],
        ['id' => '5.4.6', 'category' => 'Master and All', 'text' => 'Were the lifebuoys, and associated lights, smoke floats and lifelines, in good order, clearly marked and correctly distributed around the ship?'],
        ['id' => '5.4.7', 'category' => 'Master and All', 'text' => 'Were the Master, officers and ratings familiar with the immersion suits, and were the immersion suits in good order, readily accessible and their location(s) clearly indicated?'],
        ['id' => '5.4.8', 'category' => 'Master and All', 'text' => 'Were the Master, officers and ratings familiar with the lifejackets and personal flotation devices (PFDs) provided on board, and was the equipment in good condition, and properly maintained?'],
        ['id' => '5.4.9', 'category' => 'Master and Chief Engineer', 'text' => 'Were the Master and officers familiar with the company procedures for the periodic testing and maintenance of the emergency lighting system, was there evidence of periodic testing, and was the system in proper operating condition?'],
        ['id' => '5.5.1', 'category' => 'Master and All', 'text' => 'Were the Master, officers and ratings familiar with the company enclosed space entry procedures, and was evidence available to demonstrate that all enclosed space entries had been made in strict compliance with the procedures?'],
        ['id' => '5.5.2', 'category' => 'Master and Chief Engineer', 'text' => 'Were the Master, officers and, where directly involved, ratings familiar with the company hot work procedure, and was evidence available to demonstrate that hot work had been conducted in accordance with the procedure?'],
        ['id' => '5.5.3', 'category' => 'Master and All', 'text' => 'Were the Master, officers and ratings familiar with the company procedure for working at height, and was there evidence that risk control measures such as permits to work or documented risk assessments were consistently used whenever work was undertaken at height?'],
        ['id' => '5.5.4', 'category' => 'Master and All', 'text' => 'Were the Master, officers and ratings familiar with the company procedures for working over the side, and was there evidence that risk control measures such as standard work procedures, permits to work or documented risk assessments were consistently used whenever work was undertaken over the side?'],
        ['id' => '5.5.5', 'category' => 'Chief Engineer and Engineers', 'text' => 'Were the Master and officers familiar with the company procedures for working on electrical equipment and systems, and was there evidence that risk control measures such as permits to work and/or documented risk assessments were consistently used whenever work was undertaken on electrical equipment and systems?'],
        ['id' => '5.5.6', 'category' => 'Chief Engineer and Engineers', 'text' => 'Were the Master and officers familiar with the company procedures for the control of hazardous energy, and was evidence available, through documented risk assessment or permits, that hazardous energy sources were routinely identified and isolated before working on, or in, machinery, systems or spaces where hazardous energy could be present?'],
        ['id' => '5.6.1', 'category' => 'Chief Officer and Officers', 'text' => 'Were the Master and officers familiar with the purpose, operation, testing, maintenance and calibration of the vessel\'s portable and personal gas measurement instruments, and was the equipment on board sufficient, in good working order, regularly tested and periodically calibrated?'],
        ['id' => '5.6.2', 'category' => 'Chief Officer and Officers', 'text' => 'Were the Master and deck officers familiar with the company procedures for testing the atmosphere in double-hull and double bottom spaces for flammable gas, and were records available to confirm that appropriate measurements had been taken using the equipment fitted to, or provided on, the vessel?'],
        ['id' => '5.6.3', 'category' => 'Chief Officer and Officers', 'text' => 'Were the Master and officers familiar with the location, purpose and operation of the vessel\'s fixed gas detection systems required by the IGC Code, and was the equipment in good working order, regularly maintained and calibrated?'],
        ['id' => '5.6.5', 'category' => 'Chief Officer and Officers', 'text' => 'Were the Master and officers familiar with the operation and maintenance of the cargo pump room fixed gas detection system, and was the equipment fully operational with sensors calibrated and alarm activation points set in accordance with company procedures and manufacturer\'s instructions?'],
        ['id' => '5.6.6', 'category' => 'Master and All', 'text' => 'Were the Master and officers familiar with the operation and maintenance of the oxygen sensors and associated alarms fitted in the space, or spaces, containing the inert gas system, and was the equipment fully operational with sensors calibrated and alarm activation points set in accordance with company procedures and manufacturer\'s instructions?'],
        ['id' => '5.7.1', 'category' => 'Master', 'text' => 'Had all onboard incidents been reported and investigated in accordance with company procedures, and was an incident investigation report or a summarised lessons learned bulletin available for each incident at or above a defined threshold?'],
        ['id' => '5.7.2', 'category' => 'Master and All', 'text' => 'Were the Master, officers and ratings familiar with the company incident and near-miss reporting procedure and was evidence available to demonstrate that incidents and near-misses had been investigated and closed out in accordance with the company procedure?'],
        ['id' => '5.7.3', 'category' => 'Master', 'text' => 'Were the Master, officers and ratings familiar with the company procedure for holding and documenting shipboard safety meetings and was evidence available that safety concerns raised at the meetings were acknowledged and addressed by shore management?'],
        ['id' => '5.7.4', 'category' => 'Master and Chief Engineer', 'text' => 'Were the Master, officers and ratings familiar with the company work planning procedures and were records available to demonstrate that onboard work planning meetings had been conducted and documented in accordance with the procedures?'],
        ['id' => '5.7.5', 'category' => 'Master and All', 'text' => 'Were the Master, officers and ratings familiar with the purpose and implementation of the company Stop Work Authority policy and procedure?'],
        ['id' => '5.7.6', 'category' => 'Master and All Crew', 'text' => 'Were the Master, officers and ratings familiar with the company procedures for risk assessment, as appropriate to their duties, and was there evidence of the development and review of risk assessments in accordance with the procedures?'],
        ['id' => '5.7.7', 'category' => 'Chief Officer and 2nd Engineer', 'text' => 'Were Safety Data Sheets (SDS) available on board for all  cargo, bunkers, chemicals, paints and other products being handled, and were crew members familiar with their use?'],
        ['id' => '5.7.8', 'category' => 'Master and Chief Engineer', 'text' => 'Were the Master, officers and ratings familiar with the company Simultaneous Operations (SIMOPS) procedure and was there evidence that SIMOPS were considered during work planning and the required controls implemented for the duration of such operations?'],
        ['id' => '5.8.1', 'category' => 'Master and Chief Officer', 'text' => 'Were the Master and officers familiar with the company procedure for safety inspections of the main deck areas, and had inspections been effective in identifying hazards to health, safety and the environment?'],
        ['id' => '5.8.2', 'category' => 'Master and Chief Engineer', 'text' => 'Were the Master and officers familiar with the company procedure for safety inspections of the machinery spaces, and had inspections been effective in identifying hazards to health, safety and the environment?'],
        ['id' => '5.8.3', 'category' => 'Chief Officer and Officers', 'text' => 'Were the Master and officers familiar with the company procedure for safety inspections of the cargo pumproom, and had inspections been effective in identifying hazards to health, safety and the environment?'],
        ['id' => '5.8.5', 'category' => 'Chief Officer and Officers', 'text' => 'Were the Master and officers familiar with the company procedure for safety inspections of the forecastle, and had inspections been effective in identifying hazards to health, safety and the environment?'],
        ['id' => '5.8.6', 'category' => 'Master', 'text' => 'Were the Master and officers familiar with the company procedure for safety inspections of the accommodation, and had inspections been effective in identifying hazards to health, safety and the environment?'],
        ['id' => '5.8.7', 'category' => 'Chief Officer', 'text' => 'Were the Master and officers familiar with the company procedure for safety inspections of the ballast and/or bunker pumproom, and had inspections been effective in identifying hazards to health, safety and the environment?'],
        ['id' => '5.9.1', 'category' => 'Master and All', 'text' => 'Were the Master, officers and ratings familiar with the company lifting and rigging procedures, and was evidence available to demonstrate that each item of lifting and rigging equipment had been maintained, inspected and tested in accordance with the procedure?'],
        ['id' => '5.9.2', 'category' => 'Chief Engineer', 'text' => 'Where the vessel was fitted with a single cargo hose handling crane, was a risk assessment available which identified the minimum spare parts that must be carried onboard to ensure continued operation in the event of a single component failure, and were the identified spare parts available onboard?'],
        ['id' => '5.10.1', 'category' => 'Master and All Deck Staff', 'text' => 'Were the Master, deck officers and deck ratings familiar with the company procedures for rigging the pilot boarding arrangements, and was the equipment provided in satisfactory condition and used in accordance with industry best practice?'],
        ['id' => '5.10.2', 'category' => 'Master and All Deck Staff', 'text' => 'Were the Master, deck officers and deck ratings familiar with the company procedures for rigging the accommodation ladders, and were the accommodation ladders in good order and used in accordance with the company procedure and manufacturer\'s instructions?'],
        ['id' => '5.10.3', 'category' => 'Master and All Deck Staff', 'text' => 'Were the Master, officers and ratings familiar with the company procedure for providing safe access to the vessel while alongside a terminal/berth, and was safe access provided by the ship\'s portable gangway, the vessel\'s accommodation ladder or a shore gangway?'],
        ['id' => '5.10.5', 'category' => 'Master and All Deck Staff', 'text' => 'Were the Master and officers familiar with the company procedures for helicopter/ship operations, and had these procedures been complied with?'],
        ['id' => '5.10.6', 'category' => 'Master and All Deck Staff', 'text' => 'Were the Master and officers familiar with the company procedures for helicopter/ship operations, and had the crew involved received appropriate training?'],
        ['id' => '5.10.7', 'category' => 'Master and Chief Engineer', 'text' => 'Were the Master, officers and crew familiar with the escape routes from the machinery spaces, pump rooms, compressor rooms, accommodation spaces and, when in port, from the vessel, and were these routes clearly marked, unobstructed and well illuminated?'],
        ['id' => '5.11.1', 'category' => 'Chief Officer and Chief Engineer', 'text' => 'Were the Master and officers familiar with the company procedures addressing the management of samples of bunker fuel oil and Annex I and/or Annex II cargoes as applicable, and were samples being properly stored and eventually disposed of?'],
        ['id' => '5.12.1', 'category' => 'Master', 'text' => 'Were the Master, officers and ratings familiar with the company procedures that addressed the use of respiratory protective equipment during cargo operations, and did the procedures prohibit the use of filter type respirators for this purpose?'],
        ['id' => '5.12.2', 'category' => 'Master and All Deck Staff', 'text' => 'Were the Master, officers and ratings familiar with the location and operation of the decontamination showers and eyewash stations on deck, and were these facilities suitably marked, easily accessible and ready for use?'],
        ['id' => '6.1.1', 'category' => 'Chief Officer', 'text' => 'Were the Master and officers familiar with the company procedure for maintaining the Cargo Record Book, and did the entries contained in the Cargo Record Book accurately record the cargo related operations required to be documented by MARPOL Annex II?'],
        ['id' => '6.1.2', 'category' => 'Chief Officer', 'text' => 'Were the Master and officers familiar with the company procedure for maintaining the Oil Record Book Part II, and did the entries contained in the Oil Record Book Part II accurately record the cargo related operations required to be documented by MARPOL Annex I?'],
        ['id' => '6.1.3', 'category' => 'Chief Officer', 'text' => 'Were the Master and engineer officers familiar with the company procedure for maintaining the Oil Record Book Part I, and did the entries contained in the Oil Record Book Part I accurately record the machinery space operations required to be documented by MARPOL Annex I?'],
        ['id' => '6.1.4', 'category' => 'Chief Officer', 'text' => 'Were the Master and officers familiar with the company procedures for maintaining the Garbage Record Book in accordance with the Garbage Management Plan, and did the entries contained in the Garbage Record Book accurately record the garbage management activities required to be documented by MARPOL Annex V?'],
        ['id' => '6.1.5', 'category' => 'Chief Engineer', 'text' => 'Were the Master and engineer officers familiar with the company procedure for maintaining the Ozone-depleting Substances Record Book, and did the entries contained in the Ozone-depleting Substances Record Book accurately record the operations and emissions required to be documented by MARPOL Annex VI?'],
        ['id' => '6.1.6', 'category' => 'Chief Engineer', 'text' => 'Were the documents and records required by MARPOL Annex VI Regulation 13 for the control of NOx and associated emissions in good order?'],
        ['id' => '6.2.1', 'category' => 'Chief Officer', 'text' => 'Were the Master and officers familiar with the arrangements to drain the cargo pumproom bilges in the event of flooding or accidental leakage, and were these arrangements in good order?'],
        ['id' => '6.2.2', 'category' => 'Chief Officer', 'text' => 'Were cargo system overboard and sea suction valves checked and verified as closed and secured prior to commencement of cargo transfer, and where provided, were sea valve-testing arrangements in order and regularly monitored for leakage?'],
        ['id' => '6.2.3', 'category' => 'Chief Engineer', 'text' => 'Were the Master and officers familiar with the company procedures for inspections and pressure tests of the bunker oil (HFO and MDO) pipeline system, and had the tests been performed and the results suitably recorded?'],
        ['id' => '6.3.1', 'category' => 'Chief Engineer and Chief Officer', 'text' => 'Were the Master and officers familiar with the company procedures for the safe operation of the ballast water management system (BWMS), and was the equipment in satisfactory condition and used in accordance with the company procedures and manufacturer\'s instructions?'],
        ['id' => '6.4.1', 'category' => 'Master and All', 'text' => 'Were the Master, officers and ratings familiar with the company procedures for the removal of small quantities of oil or chemical spilled and contained on deck, and was suitable response equipment available, in satisfactory condition and effectively deployed?'],
        ['id' => '6.4.2', 'category' => 'Master and All', 'text' => 'Were the Master and officers familiar with the company procedures for the disposal of accumulations of water contaminated with oil and/or marine pollutants in the forecastle and other internal spaces, and had the procedures been implemented?'],
        ['id' => '6.5.1', 'category' => 'Chief Engineer', 'text' => 'Were the Master and officers familiar with the emergency arrangements to pump out the machinery space bilges in the event of flooding, and were these arrangements prominently marked and in good order?'],
        ['id' => '6.5.2', 'category' => 'Engineers', 'text' => 'Were the engineer officers familiar with the company procedure for the safe use of the incinerator, and was the incinerator in satisfactory condition and used in accordance with the company procedure and in compliance with MARPOL?'],
        ['id' => '6.6.1', 'category' => 'Engineers', 'text' => 'Were the Master and engineer officers familiar with the company procedures for the use of the oil filtering equipment, and was the oil filtering equipment in satisfactory condition and used in accordance with the company procedure, manufacturer\'s instructions and MARPOL Annex I?'],
        ['id' => '6.6.2', 'category' => 'Chief Officer', 'text' => 'Were the Master and officers familiar with the company procedures for the use of the oil discharge monitoring and control system, and was the oil discharge monitoring and control system in satisfactory condition and used in accordance with the company procedures, manufacturer\'s instructions and MARPOL Annex I?'],
        ['id' => '7.1.1', 'category' => 'Master and All Deck Officers', 'text' => 'Was security threat and risk assessment an integral part of voyage planning, and did the passage plan contain security related information for each leg of the voyage?'],
        ['id' => '7.2.1', 'category' => 'Master and All Deck Officers', 'text' => 'Were the Master and officers familiar with the company procedures for hardening the vessel when entering areas of increased security risk, and was there a Vessel Hardening Plan (VHP) available?'],
        ['id' => '7.2.2', 'category' => 'Master and All Deck Staff', 'text' => 'Were the Master, officers and ratings familiar with the company procedures to control access to the vessel in port and to ensure the safety of visitors, and were these procedures effectively implemented?'],
        ['id' => '7.3.1', 'category' => 'Master', 'text' => 'Were the Master and officers familiar with regional maritime security reporting requirements and operation of the ship security alert system (SSAS) and had this equipment been regularly tested?'],
        ['id' => '7.4.1', 'category' => 'Chief Officer', 'text' => 'Did the Ship Security Officer (SSO) have a valid Certificate of Proficiency and a full understanding of their role, and were ship security records of port calls being maintained as required by SOLAS?'],
        ['id' => '7.5.1', 'category' => 'Master', 'text' => 'Were the Master and officers familiar with the company procedures for cyber security risk management, and had these procedures been fully implemented?'],
        ['id' => '8.1.1', 'category' => 'Master and Chief Engineer', 'text' => 'Were the Master and officers familiar with the company procedures for the use of the inert gas system, and had the inert gas system been used in accordance with ISGOTT guidance, with cargo tanks maintained in an inert condition at all times, except when it was necessary to be gas-free for entry?'],
        ['id' => '8.1.2', 'category' => 'Chief Officer', 'text' => 'Were the Master and officers familiar with the company procedures and international regulations for the planning, preparation, conduct and documentation of crude oil washing operations (COW), and was the COW system in satisfactory condition and used in accordance with the company procedures for each COW operation?'],
        ['id' => '8.1.3', 'category' => 'Chief Officer', 'text' => 'Were the Master and officers familiar with the company procedures for the isolation of individual cargo tanks from the common venting system in accordance with SOLAS, and were these procedures being followed?'],
        ['id' => '8.1.4', 'category' => 'Chief Officer', 'text' => 'Were the Master and deck officers familiar with the company procedures for planning and documenting cargo tank cleaning operations after the carriage of volatile products, and had these procedures been followed?'],
        ['id' => '8.2.1', 'category' => 'Master', 'text' => 'Were the Master and officers familiar with the company procedures for the operation of the inert gas system, and had the inert gas system been used in accordance with these procedures, industry guidance, and SOLAS and IBC regulations?'],
        ['id' => '8.2.2', 'category' => 'Master and All Deck Officers', 'text' => 'Were the Master and officers familiar with the company procedures that addressed the carriage of inhibited cargoes, and had these procedures been followed?'],
        ['id' => '8.2.3', 'category' => 'Master and All Deck Officers', 'text' => 'Were the Master and officers familiar with the information contained in the Procedures and Arrangements Manual, Certificate of Fitness for the Carriage of Noxious Liquid Substances in Bulk, the IBC Code and the latest MEPC.2/Circular, and was this information readily available to the officers engaged in cargo planning and operations?'],
        ['id' => '8.2.4', 'category' => 'Master and All Deck Officers', 'text' => 'Were the Master and deck officers familiar with the company procedures for planning and documenting cargo tank cleaning operations after the carriage of volatile and/or toxic products, and had these procedures been followed?'],
        ['id' => '8.2.5', 'category' => 'Master and All Deck Officers', 'text' => 'Were the Master and deck officers familiar with the company procedures for identifying and segregating incompatible cargoes during cargo stowage planning, and had these procedures been followed?'],
        ['id' => '8.2.6', 'category' => 'Master and All Deck Officers', 'text' => 'Were there sufficient escape sets as required by the IBC Code for everyone on board, and did the sets provide suitable respiratory and eye protection?'],
        ['id' => '8.2.7', 'category' => 'Master and All Deck Officers', 'text' => 'Were the Master and officers familiar with the company procedures relating to the safety equipment required by the IBC Code, including SCBAs, and was the equipment in satisfactory condition ready for immediate use?'],
        ['id' => '8.2.8', 'category' => 'Master and All Deck Officers', 'text' => 'Were the Master and officers familiar with the company procedures addressing the protective equipment required by the IBC Code, and was this equipment in satisfactory condition and suitable for the products being handled?'],
        ['id' => '8.3.1', 'category' => 'Chief Engineer', 'text' => 'Were the Master and officers familiar with the purpose, operation and testing of the inert gas generator, and had the system been operated and maintained in accordance with the manufacturer\'s instructions and company procedures?'],
        ['id' => '8.3.2', 'category' => 'Chief Engineer', 'text' => 'Were the Master and officers familiar with the purpose, operation and testing of the nitrogen generator inert gas system, and had the system been operated and maintained in accordance with the manufacturer\'s instructions and company procedures?'],
        ['id' => '8.3.3', 'category' => 'Chief Engineer and Engineers', 'text' => 'Were the Master and officers familiar with the purpose, operation and testing of the flue gas inert gas system, and had the system been operated and maintained in accordance with the manufacturer\'s instructions and company procedures?'],
        ['id' => '8.3.4', 'category' => 'Master and all Officers', 'text' => 'Were the Master and officers familiar with the company procedures for the maintenance, testing and setting of the cargo tank high-level and high-high-level alarms, and were these alarm systems fully operational and properly set?'],
        ['id' => '8.3.5', 'category' => 'Master and all Officers', 'text' => 'Were the Master, deck officers and deck ratings familiar with the company procedures for dipping, ullaging and sampling flammable static accumulator cargoes in non-inerted tanks, and were these procedures being followed?'],
        ['id' => '8.3.6', 'category' => 'Master and all Officers', 'text' => 'Were the Master and deck officers familiar with the company procedures for loading flammable static accumulator cargoes into non-inerted tanks, and were these procedures being followed?'],
        ['id' => '8.3.7', 'category' => 'Chief Engineer and Engineers', 'text' => 'Were the Master and officers familiar with the purpose, operation and calibration of the inert gas system fixed oxygen analyser, and had the equipment been operated, maintained and calibrated in accordance with the manufacturer\'s instructions and company procedures?'],
        ['id' => '8.3.8', 'category' => 'Master and all Officers', 'text' => 'Were the Master, officers and ratings familiar with the cargo system Emergency Shutdown (ESD) system, where fitted, and/or the cargo pump emergency stop controls, and was there evidence that the systems and equipment had been tested in accordance with company procedures?'],
        ['id' => '8.3.9', 'category' => 'Master and all Officers', 'text' => 'Were the Master and officers familiar with the company procedures for the inspection and testing of cargo, vapour and inert gas pipelines, and were records available for these activities?'],
        ['id' => '8.3.10', 'category' => 'Master and all Officers', 'text' => 'Were the Master and officers familiar with the company procedures for the inspection, testing and operation of the vapour collection system, and was this equipment in satisfactory condition?'],
        ['id' => '8.3.11', 'category' => 'Master and all Officers', 'text' => 'Were the Master, deck officers and deck ratings familiar with the company procedures for cargo tank washing after the carriage of volatile products in a non-inert atmosphere, and had these procedures been followed?'],
        ['id' => '8.3.12', 'category' => 'Master and all Officers', 'text' => 'Were the Master and officers familiar with the company procedures for the use of portable cargo ullage/temperature/interface (UTI) measurement and sampling equipment, and was the equipment in satisfactory condition and used in accordance with the company procedures?'],
        ['id' => '8.3.13', 'category' => 'Master and all Officers', 'text' => 'Were the Master and officers familiar with the company procedures for the operation of the primary and secondary cargo tank venting systems in accordance with SOLAS, and were these systems correctly set?'],
        ['id' => '8.3.14', 'category' => 'Master and all Officers', 'text' => 'Were the Master and officers familiar with the company procedures for the operation, inspection, testing and maintenance of the cargo tank venting systems, and were the systems in satisfactory condition?'],
        ['id' => '8.3.15', 'category' => 'Master and all Officers', 'text' => 'Were the Master and officers familiar with the company procedures for monitoring leakage into the cofferdams of deepwell pumps, and had regular purging of the cofferdams taken place to identify any excessive leakage?'],
        ['id' => '8.3.16', 'category' => 'Master and all Officers', 'text' => 'Were the Master and officers familiar with the purpose, operation, testing and maintenance of the non-return devices installed in the inert gas system, and were these devices in satisfactory condition?'],
        ['id' => '8.3.17', 'category' => 'Master and all Officers', 'text' => 'Were the Master and officers familiar with the company procedures for the use, inspection and testing of manifold reducers, spool pieces and other portable pipework, and were these items in satisfactory condition and properly fitted when in use?'],
        ['id' => '8.3.18', 'category' => 'Master and all Officers', 'text' => 'Were the Master and officers familiar with the purpose, operation, testing and maintenance of the pressure/vacuum-breaking (P/V) device(s) installed in the inert gas main, and was this device(s) in satisfactory condition?'],
        ['id' => '8.3.19', 'category' => 'Master and all Officers', 'text' => 'Were the Master and officers familiar with the purpose, operation and testing of the indicators and alarms in the inert gas system, and had the equipment been operated, maintained and calibrated in accordance with the manufacturer\'s instructions and company procedures?'],
        ['id' => '8.3.20', 'category' => 'Master and all Officers', 'text' => 'Were the Master and officers familiar with the purpose and operation of the connections and interconnections to the inert gas system for routine and emergency inert gas operations, and were these arrangements in satisfactory condition and clearly identified as to their purpose?'],
        ['id' => '8.3.21', 'category' => 'Master and all Officers', 'text' => 'Were the Master and officers familiar with the company procedure for cargo heating, and was the cargo heating system in satisfactory condition and tested and used in accordance with the company procedure?'],
        ['id' => '8.3.22', 'category' => 'Master and all Officers', 'text' => 'Were the Master and officers familiar with the company procedures for managing on-board doping operations, and had these procedures been complied with?'],
        ['id' => '8.3.23', 'category' => 'Master and all Officers', 'text' => 'Were the Master and officers familiar with the company procedures for the maintenance, testing and calibration of the cargo temperature monitoring equipment, and was the equipment in satisfactory condition?'],
        ['id' => '8.3.24', 'category' => 'Master and all Officers', 'text' => 'Were the Master and officers familiar with the company procedures for managing cargo and vapour connections at the cargo manifolds, and were the manifold arrangements in satisfactory condition?'],
        ['id' => '8.3.25', 'category' => 'Master and all Officers', 'text' => 'Were the Master and deck officers familiar with the company procedures for receiving nitrogen from shore for operations such as inerting, purging or padding cargo tank, or for clearing cargo lines?'],
        ['id' => '8.4.1', 'category' => 'Master and all Officers', 'text' => 'Were the Master and officers familiar with the company procedures that addressed the carriage of inhibited cargoes, and had these procedures been followed?'],
        ['id' => '8.4.2', 'category' => 'Master and all Officers', 'text' => 'Were the Master and Officers familiar with the company procedures for carrying out cargo sampling operations?'],
        ['id' => '8.4.3', 'category' => 'Master and all Officers', 'text' => 'Were the Master and officers familiar with the company procedures for identifying and segregating incompatible cargoes and refrigerants during cargo stowage planning, and had these procedures been followed?'],
        ['id' => '8.4.4', 'category' => 'Master and all Officers', 'text' => 'Were the Master and officers familiar with the company procedures for the safe carriage of propylene oxide (PO), ethylene oxide (EO) and PO-EO mixtures?'],
        ['id' => '8.6.12', 'category' => 'Master and All Officers', 'text' => 'Were the Master and officers familiar with the company procedures relating to the safety, rescue and recovery equipment, including SCBAs, required by the IGC Code, and was the equipment ready for immediate use?'],
        ['id' => '8.99.2', 'category' => 'Master and All Officers', 'text' => 'Were the Master and all officers with a direct responsibility for cargo, tank cleaning or ballast operations familiar with the requirements of the ISGOTT Ship/Shore Safety Checklist (SSSCL) and, were appropriate sections of the SSSCL in use with all applicable provisions and agreements maintained throughout?'],
        ['id' => '8.99.3', 'category' => 'Master and All Officers', 'text' => 'Were the Master and officers familiar with the company procedures which provided guidance on the level of supervision and support for cargo / port operations, and were operations supervised and supported by an appropriate team in accordance with the company procedures?'],
        ['id' => '8.99.4', 'category' => 'Master and All Officers', 'text' => 'Were the Master and officers familiar with the company procedures for checking and testing cargo and ballast system valves, and were the valves and the remote control system in satisfactory condition?'],
        ['id' => '8.99.5', 'category' => 'Master and All Officers', 'text' => 'Were the Master and officers familiar with the company procedures for the operation, maintenance, testing, calibration and comparison of the fixed cargo tank level gauging system, and was the system in satisfactory condition and fully operational?'],
        ['id' => '8.99.6', 'category' => 'Master and All Officers', 'text' => 'Were the Master and deck officers familiar with the company procedure and manufacturer\'s instructions for the periodic testing of the stability and loading instrument(s), and were records maintained to confirm that tests had been completed in accordance with the procedure?'],
        ['id' => '8.99.7', 'category' => 'Master and All Officers', 'text' => 'Where the vessel was subject to loading restrictions and/or intact stability concerns at any phase of a voyage or cargo operation, had the company developed procedures to manage these restrictions and/or concerns, and were the Master and cargo officers familiar with the company procedures?'],
        ['id' => '8.99.8', 'category' => 'Master and All Officers', 'text' => 'Were the Master and officers familiar with the company procedures for the selection, inspection, testing and storage of cargo transfer hoses, and were the hoses in satisfactory condition?'],
        ['id' => '8.99.9', 'category' => 'Master and All Officers', 'text' => 'Were the Master and officers familiar with the company procedures for periodically verifying the accuracy of cargo and ballast system controls and indicators, and were legible and up-to-date pipeline and/or mimic diagrams available at the cargo control location(s) and in the pumproom(s) as applicable?'],
        ['id' => '8.99.10', 'category' => 'Master and All Officers', 'text' => 'Were the Master and officers a familiar with the company procedures for the inspection and maintenance of the bonding arrangements for independent cargo tanks, process plant and cargo pipelines and, were these arrangements in satisfactory condition?'],
        ['id' => '8.99.11', 'category' => 'Master and All Officers', 'text' => 'Was there a procedure in place to complete an independent check of the entire cargo liquid, vapour and venting pipeline system prior to commencement of cargo operations to ensure that valves, vacuum breakers, sampling connections, drains and unused connections or interconnections were correctly set, and blanked or capped, where appropriate?'],
        ['id' => '9.1.1', 'category' => 'Master and All Officers', 'text' => 'Were the Master and deck officers familiar with the company procedures for the testing and correct operation of the mooring winch brakes, and were records available to demonstrate that brakes had been tested periodically, after maintenance or when there was evidence of premature brake slippage?'],
        ['id' => '9.1.2', 'category' => 'Master and All Officers', 'text' => 'Was the vessel satisfactorily moored in accordance with both the terminal mooring plan and the mooring configurations permitted by the vessel\'s Mooring System Management Plan?'],
        ['id' => '9.1.3', 'category' => 'Master and All Officers', 'text' => 'Were the Master, deck officers, and ratings involved with mooring operations, familiar with the content of the Line Management Plan and was the plan maintained in accordance with company instructions with mooring line, mooring tail and joining shackle certificates available for each item included within the Line Management Plan?'],
        ['id' => '9.1.4', 'category' => 'Master and All Officers', 'text' => 'Did all mooring lines, mooring tails and joining shackles, including those carried as spares, meet industry guidelines?'],
        ['id' => '9.2.1', 'category' => 'Master and All Officers', 'text' => 'Were the Master and all officers familiar with the vessel specific emergency towing procedure, and was the emergency towing equipment, where fitted, in satisfactory condition and ready for immediate use?'],
        ['id' => '9.3.1', 'category' => 'Master and All Officers', 'text' => 'Were the Master and deck officers familiar with the company procedures for anchoring operations, and were records available to confirm that recent anchoring operations had been conducted in compliance with company expectations?'],
        ['id' => '9.4.1', 'category' => 'Master and All Officers', 'text' => 'Were the Master, deck officers and deck ratings familiar with the company procedure that defined mooring team supervision and composition for the various mooring and anchoring operations likely to be undertaken, and was evidence available that each mooring work space had been supervised and manned in accordance with company expectations?'],
        ['id' => '9.4.2', 'category' => 'Master and All Officers', 'text' => 'Were the deck officers and ratings involved with mooring operations familiar with the safe operation of the mooring winches and the dangers of working with and around mooring lines during mooring operations and while under tension?'],
        ['id' => '9.5.1', 'category' => 'Master and All Officers', 'text' => 'Were the appropriate industry checklists used during STS operations, and were comprehensive records of these operations maintained?'],
        ['id' => '9.5.2', 'category' => 'Master and All Officers', 'text' => 'Where the vessel was involved in an "at sea" STS operation, was an accurate Joint Plan of Operation available onboard, were the Master and deck officers familiar with its content, and were operations being conducted in accordance with its requirements?'],
        ['id' => '9.5.3', 'category' => 'Master and All Officers', 'text' => 'Were the Master, officers and deck ratings familiar with the vessel\'s STS Operations Plan?'],
        ['id' => '9.6.1', 'category' => 'Master and All Officers', 'text' => 'Were the vapour collection system manifold arrangements suitable for hose handling at buoy moorings?'],
        ['id' => '9.6.2', 'category' => 'Master and All Officers', 'text' => 'Were the Master and officers familiar with the company procedures for mooring at an SPM or F(P)SO and were the fittings required accurately described in the HVPQ?'],
        ['id' => '10.1.1', 'category' => 'Chief Engineer and Engineers', 'text' => 'Had the Chief Engineer prepared Standing Orders, supplemented by Daily Orders, which emphasised and reinforced the company expectations with regards to engine room management and, if so, had all engineer officers signed to acknowledge their understanding of the same?'],
        ['id' => '10.1.2', 'category' => 'Chief Engineer and Engineers', 'text' => 'Were the Chief Engineer and engineer officers familiar with the company procedures for testing main propulsion, steering gear, thrusters and power generation plant prior to use and at critical points during a voyage or operation, and were checklists and log book entries completed as required?'],
        ['id' => '10.1.3', 'category' => 'Chief Engineer and Engineers', 'text' => 'Were the Chief Engineer and engineer officers familiar with company procedures for periodic rounds and monitoring of the machinery space, and were log book entries and checklists available to confirm that the rounds had been completed as required?'],
        ['id' => '10.1.4', 'category' => 'Chief Engineer and Engineers', 'text' => 'Were the Chief Engineer and engineer officers familiar with company procedures for periodic machinery space rounds and monitoring of the machinery space during both manned and unmanned (UMS) periods, and were log book entries and checklists available to confirm that the inspections had been completed as required?'],
        ['id' => '10.1.5', 'category' => 'Chief Engineer and Engineers', 'text' => 'Were the Chief Engineer and engineer officers familiar with the operation, inspection and testing of the means provided to control propulsion machinery and related auxiliary systems locally in the event of failure of a remote-control system?'],
        ['id' => '10.2.1', 'category' => 'Chief Engineer and Engineers', 'text' => 'Were the officers familiar with the starting procedure for the emergency generator and were records available to demonstrate that the emergency generator had been tested according to company procedures?'],
        ['id' => '10.2.2', 'category' => 'Chief Engineer and Engineers', 'text' => 'Were the Chief Engineer and engineer officers familiar with the company procedures for the regular inspection, maintenance and testing of the ship\'s emergency batteries, and were the batteries fully charged and in satisfactory condition?'],
        ['id' => '10.2.4', 'category' => 'Chief Engineer and Engineers', 'text' => 'Were seawater pipelines, sea chests and seawater pumps in satisfactory condition and free of temporary repairs?'],
        ['id' => '10.2.5', 'category' => 'Chief Engineer and Engineers', 'text' => 'Were the officers familiar with the company procedure for testing the bilge monitoring devices within their area of responsibility, and were records available to demonstrate that the bilge monitoring devices and associated alarms had been tested in accordance with the company procedure?'],
        ['id' => '10.2.6', 'category' => 'Chief Engineer and Engineers', 'text' => 'Were the Chief Engineer and engineer officers familiar with the company procedures for the operation, inspection and testing of the emergency air compressor and emergency air reservoir, and was the equipment in satisfactory condition?'],
        ['id' => '10.3.1', 'category' => 'Chief Engineer and Engineers', 'text' => 'Was suitable deck insulation provided to the front and rear of electrical switchboards, and was it in good order?'],
        ['id' => '10.3.2', 'category' => 'Chief Engineer and Engineers', 'text' => 'Were the engineer officers familiar with the purpose and setting of the insulation monitoring devices provided on the primary and secondary distribution systems, and were the distribution switchboards free of significant earth faults?'],
        ['id' => '10.3.3', 'category' => 'Chief Engineer and Engineers', 'text' => 'Were the Chief Engineer and engineer officers familiar with the company procedures for safe entry into the machinery space(s) during UMS operation, including the operation and testing of the dead man alarm, if fitted?'],
        ['id' => '10.3.4', 'category' => 'Chief Engineer and Engineers', 'text' => 'Were the Chief Engineer and engineer officers familiar with the operation of the engineers\' alarm, and was the alarm in good order, tested regularly and the results recorded?'],
        ['id' => '10.3.5', 'category' => 'Chief Engineer and Engineers', 'text' => 'Were the Chief Engineer and engineer officers familiar with the operation of the machinery alarm, and was the alarm in good order, tested regularly and the results recorded?'],
        ['id' => '10.3.6', 'category' => 'Chief Engineer and Engineers', 'text' => 'Were the Master and officers familiar with the company procedures for the operation, inspection and regular testing of watertight doors, and were the watertight doors in satisfactory condition?'],
        ['id' => '10.3.7', 'category' => 'Chief Engineer and Engineers', 'text' => 'Was gas welding and cutting equipment in good order, and spare oxygen and acetylene cylinders stored apart in a well-ventilated location outside of the accommodation and engine room?'],
        ['id' => '10.3.8', 'category' => 'Chief Engineer and Engineers', 'text' => 'Were engineer officers and ratings familiar with the safety precautions for the use of electric welding equipment, were these safety precautions posted, and was the equipment in satisfactory condition?'],
        ['id' => '10.4.1', 'category' => 'Chief Engineer and Engineers', 'text' => 'Were the responsible vessel staff familiar with the company procedure for managing and using the planned maintenance system, and was the system updated with an accurate record of onboard maintenance and spare parts in accordance with the procedure?'],
        ['id' => '10.4.2', 'category' => 'Chief Engineer and Engineers', 'text' => 'Did the vessel operator subscribe to a lube oil and hydraulic oil analysis program and was a procedure in place to act on the results and trends identified by the analysis?'],
        ['id' => '10.5.1', 'category' => 'Chief Engineer and Engineers', 'text' => 'Were the Master, Chief Engineer, officers, and ratings involved in bunkering operations, familiar with the company bunkering procedures, and were records available to demonstrate that bunker operations had been planned and conducted in accordance with the company procedure?'],
        ['id' => '10.5.2', 'category' => 'Chief Engineer and Engineers', 'text' => 'Were the Chief Engineer and engineer officers familiar with the company procedures for bunker fuel oil sampling and analysis, and were records available to demonstrate that samples had been taken and retained or analysed in accordance with the procedure?'],
        ['id' => '10.5.3', 'category' => 'Chief Engineer and Engineers', 'text' => 'Were the Chief Engineer and senior engineer officers familiar with the company and vessel specific fuel changeover procedures, and were records available to demonstrate that fuel grade changeovers had been completed in compliance with the procedures and MARPOL regulations?'],
        ['id' => '10.7.1', 'category' => 'Chief Engineer and Engineers', 'text' => 'Were the Master and officers familiar with the location, purpose, testing and operation of the vessel\'s remote controls for fuel and lube oil valves, emergency fuel and lube oil pump shut-offs and oil tank quick closing valves, and were the systems in good working order?'],
        ['id' => '10.7.2', 'category' => 'Chief Engineer and Engineers', 'text' => 'Were the Master and officers familiar with the measures to prevent fire in the machinery spaces caused by flammable liquid spraying onto a hot surface and, were the protective measures provided regularly inspected and properly maintained?'],
        ['id' => '10.7.3', 'category' => 'Chief Engineer and Engineers', 'text' => 'Were the main engine crankcase oil mist detectors, engine bearing temperature monitors or equivalent devices and associated alarms in good order?'],
        ['id' => '10.7.4', 'category' => 'Chief Engineer and Engineers', 'text' => 'Where hydraulic power packs were located within the main engine compartment, were fire protection measures provided, and if so, where they in satisfactory condition?'],
        ['id' => '12.1.1', 'category' => 'Master and All Officers', 'text' => 'Where the vessel traded in polar waters, had the Master, Chief Mate and officers in charge of a navigational watch undertaken the additional training required by the Polar Code?'],
        ['id' => '12.2.1', 'category' => 'Master and All Officers', 'text' => 'Were the Master and officers familiar with the company procedures to ensure the operability of the life-saving and fire-fighting systems and equipment in sub-zero temperatures, and had these procedures been complied with?'],
        ['id' => '12.3.1', 'category' => 'Master and All Officers', 'text' => 'Were the Master and officers familiar with the company procedures to ensure the operability of the engine room machinery and systems in sub-zero temperatures, and had these procedures been complied with?'],
        ['id' => '12.4.1', 'category' => 'Master and All Officers', 'text' => 'Were the Master and officers familiar with the company procedures to ensure the operability of the cargo and ballast systems in sub-zero temperatures, and had these procedures been complied with?'],
        ['id' => '12.5.1', 'category' => 'Master and All Officers', 'text' => 'Were the Master and officers familiar with the company procedures to ensure the operability of the deck machinery, including mooring systems, in sub-zero temperatures, and had these procedures been complied with?'],
        ['id' => '12.6.1', 'category' => 'Master and All Officers', 'text' => 'Were the Master and officers familiar with the company procedures for navigating in areas affected by ice, and had they received suitable training?'],
    ];
    
    /**
     * Get question text by ID
     */
    public static function getQuestionText($id): ?string
    {
        foreach (self::$questions as $question) {
            if ($question['id'] === $id) {
                return $question['text'];
            }
        }
        return null;
    }
    
    /**
     * Get full question array by ID
     */
    public static function getQuestion($id): ?array
    {
        foreach (self::$questions as $question) {
            if ($question['id'] === $id) {
                return $question;
            }
        }
        return null;
    }
    
    /**
     * Get all questions
     */
    public static function getAllQuestions(): array
    {
        return self::$questions;
    }
    
    /**
     * Get questions by category
     */
    public static function getQuestionsByCategory($category): array
    {
        return array_filter(self::$questions, function($q) use ($category) {
            return $q['category'] === $category;
        });
    }
}